 1	import { type FC, useCallback } from 'react';
 2	import { useModal } from 'src/modules/Providers/modals/ModalHOC/useModal';
 3	import { useForkliftTranslation } from 'src/utils/i18n';
 4	
 5	import type { V1beta1Provider } from '@kubev2v/types';
 6	import { Button, ButtonVariant, ToolbarItem } from '@patternfly/react-core';
 7	import { isEmpty } from '@utils/helpers';
 8	
 9	import type { InventoryHostNetworkTriple } from './utils/types';
10	import VSphereNetworkModal from './VSphereNetworkModal';
11	
12	const SelectNetworkForHostButton: FC<{
13	  selectedIds: string[];
14	  provider: V1beta1Provider;
15	  hostsData: InventoryHostNetworkTriple[];
16	}> = ({ hostsData, provider, selectedIds }) => {
17	  const { t } = useForkliftTranslation();
18	  const { showModal } = useModal();
19	
20	  const onClick = useCallback(() => {
21	    showModal(
22	      <VSphereNetworkModal provider={provider} data={hostsData} selectedIds={selectedIds} />,
23	    );
24	  }, [hostsData, provider, selectedIds, showModal]);
25	
26	  return (
27	    <ToolbarItem>
28	      <Button variant={ButtonVariant.secondary} onClick={onClick} isDisabled={isEmpty(selectedIds)}>
29	        {t('Select migration network')}
30	      </Button>
31	    </ToolbarItem>
32	  );
33	};
34	
35	export default SelectNetworkForHostButton;

